# @cctt_verify {"v":2,"sym":"sympy.utilities.matchpy_connector._get_srepr","kind":"function","src_hash":"e106939e491a5289","in":{"base":"Any"},"out":{"base":"Any"},"spec":{"lhs":"_get_srepr(exp)","rhs":"internal helper behaves correctly","over":{"base":"Any"},"name":"_get_srepr_correct"},"guarantee":"internal helper behaves correctly","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.utilities.matchpy_connector._get_srepr_correct","statement":"Path(_get_srepr(x), internal helper behaves correctly)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"017922e8278af94f"}
def _get_srepr(expr):
    s = srepr(expr)
    s = re.sub(r"WildDot\('(\w+)'\)", r"\1", s)
    s = re.sub(r"WildPlus\('(\w+)'\)", r"*\1", s)
